OWNER = "PierpaoloV"
REPO = "learning"
RAW = `https://raw.githubusercontent.com/${OWNER}/${REPO}/main`
API = `https://api.github.com/repos/${OWNER}/${REPO}`

// Fetch full file tree once to know what exists
treeJson = fetch(`${API}/git/trees/main?recursive=1`).then(r =&gt; r.json())
existingPaths = new Set((treeJson.tree || []).map(f =&gt; f.path))

async function fetchRaw(path) {
  try {
    const r = await fetch(`${RAW}/${path}`)
    if (!r.ok) return null
    return await r.text()
  } catch { return null }
}

function isSolved(content) {
  if (!content) return false
  const lines = content.split('\n').filter(l =&gt; l.trim() && !l.trim().startsWith('#') && !l.startsWith('from ') && !l.startsWith('import ') && !l.startsWith('class ') && !l.includes('Optional') && !l.includes('List'))
  const body = lines.join('').replace(/\s/g, '')
  return body !== '' && !body.endsWith('pass') && !body.includes('Writeyoursolutionhere')
}

function isWritten(content) {
  if (!content) return false
  return content.trim().length &gt; 80 && !content.includes('Write your design here') && !content.includes('Write your solution here')
}

// Monthly schedule
schedule = ({
  year: 2026,
  monthLabel: "April – May 2026",
  weekStarts: ["2026-04-18","2026-04-25","2026-05-02","2026-05-09"],
  weeks: [
    {
      label: "Week 1 · Apr 18–24",
      problems: [
        { slug: "0001-two-sum", title: "Two Sum", difficulty: "Easy" }
      ],
      systemDesign: null,
      cards: { count: 10, topics: "attention, backprop, batch norm, transformer, bias-variance, loss functions, RAG, MIL, optimizers, RLHF" }
    },
    {
      label: "Week 2 · Apr 25 – May 1",
      problems: [
        { slug: "0217-contains-duplicate", title: "Contains Duplicate", difficulty: "Easy" },
        { slug: "0049-group-anagrams", title: "Group Anagrams", difficulty: "Medium" },
        { slug: "0238-product-of-array-except-self", title: "Product Except Self", difficulty: "Medium" }
      ],
      systemDesign: { slug: "url-shortener", title: "URL Shortener" },
      cards: { count: 5, topics: "dropout, CNN, precision/recall, KV cache, transfer learning & LoRA" }
    },
    {
      label: "Week 3 · May 2–8",
      problems: [
        { slug: "0125-valid-palindrome", title: "Valid Palindrome", difficulty: "Easy" },
        { slug: "0015-3sum", title: "3Sum", difficulty: "Medium" },
        { slug: "0020-valid-parentheses", title: "Valid Parentheses", difficulty: "Easy" }
      ],
      systemDesign: { slug: "key-value-store", title: "Key-Value Store" },
      cards: { count: 3, topics: "vanishing gradient, data augmentation, ML system design" }
    },
    {
      label: "Week 4 · May 9–15",
      problems: [
        { slug: "0121-best-time-to-buy-sell-stock", title: "Best Time to Buy Stock", difficulty: "Easy" },
        { slug: "0003-longest-substring-without-repeating", title: "Longest Substring No Repeat", difficulty: "Medium" },
        { slug: "0206-reverse-linked-list", title: "Reverse Linked List", difficulty: "Easy" }
      ],
      systemDesign: { slug: "rate-limiter", title: "Rate Limiter" },
      cards: { count: 2, topics: "contrastive learning, LLM agents" }
    }
  ]
})

// Determine current week (0-indexed)
currentWeekIdx = {
  const today = new Date()
  const starts = schedule.weekStarts.map(s =&gt; new Date(s))
  let idx = 0
  for (let i = 0; i &lt; starts.length; i++) {
    if (today &gt;= starts[i]) idx = i
  }
  return idx
}

// Fetch all solution + review statuses in parallel
allProblems = schedule.weeks.flatMap(w =&gt; w.problems)

problemStatuses = Promise.all(
  allProblems.map(async p =&gt; {
    const paths = await existingPaths
    const content = await fetchRaw(`leetcode/${p.slug}/solution.py`)
    const solved = isSolved(content)
    const reviewed = paths.has(`leetcode/${p.slug}/review.md`)
    const reviewContent = reviewed ? await fetchRaw(`leetcode/${p.slug}/review.md`) : null
    return { slug: p.slug, solved, reviewed, reviewContent }
  })
)

statusMap = Object.fromEntries(problemStatuses.map(s =&gt; [s.slug, s]))

// Fetch system design statuses
allDesigns = schedule.weeks.filter(w =&gt; w.systemDesign).map(w =&gt; w.systemDesign)

designStatuses = Promise.all(
  allDesigns.map(async d =&gt; {
    const content = await fetchRaw(`system-design/${d.slug}/design.md`)
    return { slug: d.slug, written: isWritten(content) }
  })
)

designMap = Object.fromEntries(designStatuses.map(d =&gt; [d.slug, d]))

// Progress calculations
weekProgress = {
  const sm = await statusMap
  const week = schedule.weeks[currentWeekIdx]
  const total = week.problems.length
  const solved = week.problems.filter(p =&gt; sm[p.slug]?.solved).length
  return { solved, total, pct: total &gt; 0 ? Math.round(solved / total * 100) : 0 }
}

monthProgress = {
  const sm = await statusMap
  const total = allProblems.length
  const solved = allProblems.filter(p =&gt; sm[p.slug]?.solved).length
  return { solved, total, pct: total &gt; 0 ? Math.round(solved / total * 100) : 0 }
}







































































































































function diffBadge(d) {
  const colors = { Easy: "#22c55e", Medium: "#f59e0b", Hard: "#ef4444" }
  return `&lt;span style="background:${colors[d]||'#6b7280'};color:white;padding:1px 8px;border-radius:99px;font-size:0.72rem;font-weight:700;"&gt;${d}&lt;/span&gt;`
}

function statusIcon(ok) {
  return ok ? `&lt;span style="color:#22c55e;font-size:1rem;"&gt;✅&lt;/span&gt;`
             : `&lt;span style="color:var(--lp-status-empty);font-size:1rem;"&gt;⬜&lt;/span&gt;`
}

function bar(pct, label, sub) {
  return `
  &lt;div style="margin-bottom:1.1rem;"&gt;
    &lt;div style="display:flex;justify-content:space-between;margin-bottom:5px;"&gt;
      &lt;span style="font-weight:600;font-size:0.9rem;"&gt;${label}&lt;/span&gt;
      &lt;span style="color:var(--lp-text-muted);font-size:0.85rem;"&gt;${sub}&lt;/span&gt;
    &lt;/div&gt;
    &lt;div style="background:var(--lp-progress-bg);border-radius:999px;height:13px;overflow:hidden;"&gt;
      &lt;div style="background:linear-gradient(90deg,var(--lp-accent),var(--lp-accent-soft));width:${pct}%;height:100%;border-radius:999px;transition:width 0.6s ease;min-width:${pct&gt;0?'6px':'0'};"&gt;&lt;/div&gt;
    &lt;/div&gt;
  &lt;/div&gt;`
}

function parseGrade(content) {
  if (!content) return null
  const m = content.match(/^Grade:\s*(\d+(?:\.\d+)?\/10)/im)
  return m ? m[1] : null
}

function parseTakeHome(content) {
  if (!content) return null
  const m = content.match(/^Take-home:\s*(.+)/im)
  return m ? m[1].trim() : null
}





































// Render full page
{
  const sm = await statusMap
  const dm = await designMap
  const wp = await weekProgress
  const mp = await monthProgress

  const weekLabel = schedule.weeks[currentWeekIdx].label

  let html_out = `
  &lt;div style="max-width:860px;margin:auto;font-family:system-ui,sans-serif;"&gt;

    &lt;!-- Progress bars --&gt;
    &lt;div style="background:var(--lp-panel-bg);border:1px solid var(--lp-border);border-radius:14px;padding:1.5rem 1.75rem;margin-bottom:2rem;box-shadow:var(--lp-shadow);backdrop-filter:blur(8px);-webkit-backdrop-filter:blur(8px);"&gt;
      &lt;h3 style="margin:0 0 1.2rem;font-size:1rem;color:var(--lp-text-soft);text-transform:uppercase;letter-spacing:0.06em;"&gt;📊 Progress&lt;/h3&gt;
      ${bar(wp.pct, `This week — ${weekLabel}`, `${wp.solved} / ${wp.total} problems`)}
      ${bar(mp.pct, `Month 1 — ${schedule.monthLabel}`, `${mp.solved} / ${mp.total} problems · ${schedule.weeks.flatMap(w=&gt;w.problems).filter(p=&gt;sm[p.slug]?.reviewed).length} reviewed`)}
    &lt;/div&gt;

    &lt;!-- Year --&gt;
    &lt;details open&gt;
    &lt;summary style="cursor:pointer;font-size:1.25rem;font-weight:700;padding:0.4rem 0;list-style:none;"&gt;
      📁 2026
    &lt;/summary&gt;
    &lt;div style="padding-left:1.25rem;margin-top:0.5rem;"&gt;

      &lt;!-- Month --&gt;
      &lt;details open&gt;
      &lt;summary style="cursor:pointer;font-size:1.05rem;font-weight:600;padding:0.35rem 0;color:var(--lp-text-soft);"&gt;
        📅 ${schedule.monthLabel}
      &lt;/summary&gt;
      &lt;div style="padding-left:1rem;margin-top:0.5rem;"&gt;
  `

  for (let wi = 0; wi &lt; schedule.weeks.length; wi++) {
    const week = schedule.weeks[wi]
    const solved = week.problems.filter(p =&gt; sm[p.slug]?.solved).length
    const total = week.problems.length
    const icon = solved === total ? "✅" : solved &gt; 0 ? "🔄" : "⬜"
    const isOpen = wi === currentWeekIdx ? "open" : ""

    html_out += `
      &lt;details ${isOpen} style="margin-bottom:1rem;border:1px solid var(--lp-border);border-radius:10px;overflow:hidden;background:var(--lp-panel-bg);"&gt;
      &lt;summary style="cursor:pointer;font-size:0.97rem;font-weight:600;padding:0.75rem 1rem;background:var(--lp-panel-soft);color:var(--lp-text);list-style:none;display:flex;align-items:center;gap:0.5rem;"&gt;
        &lt;span&gt;${icon}&lt;/span&gt;
        &lt;span&gt;${week.label}&lt;/span&gt;
        &lt;span style="margin-left:auto;color:var(--lp-text-muted);font-weight:400;font-size:0.85rem;"&gt;${solved}/${total} solved&lt;/span&gt;
      &lt;/summary&gt;
      &lt;div style="padding:1rem 1.25rem;"&gt;

        &lt;!-- LeetCode --&gt;
        &lt;p style="font-size:0.78rem;font-weight:700;color:var(--lp-text-faint);text-transform:uppercase;letter-spacing:0.07em;margin:0 0 0.6rem;"&gt;💻 LeetCode&lt;/p&gt;
        &lt;table style="width:100%;border-collapse:collapse;font-size:0.86rem;margin-bottom:1.25rem;color:var(--lp-text-soft);"&gt;
          &lt;thead&gt;
            &lt;tr style="border-bottom:2px solid var(--lp-border);color:var(--lp-text-muted);font-size:0.8rem;"&gt;
              &lt;th style="padding:5px 8px;text-align:left;font-weight:600;"&gt;Problem&lt;/th&gt;
              &lt;th style="padding:5px 8px;text-align:left;font-weight:600;"&gt;Difficulty&lt;/th&gt;
              &lt;th style="padding:5px 8px;text-align:center;font-weight:600;"&gt;Solved&lt;/th&gt;
              &lt;th style="padding:5px 8px;text-align:center;font-weight:600;"&gt;Reviewed&lt;/th&gt;
            &lt;/tr&gt;
          &lt;/thead&gt;
          &lt;tbody&gt;`

    for (const p of week.problems) {
      const s = sm[p.slug] || {}
      const grade = parseGrade(s.reviewContent)
      const takeHome = parseTakeHome(s.reviewContent)
      html_out += `
            &lt;tr style="border-bottom:1px solid var(--lp-border-soft);"&gt;
              &lt;td style="padding:8px 8px;vertical-align:top;"&gt;
                &lt;a href="https://github.com/PierpaoloV/learning/tree/main/leetcode/${p.slug}" target="_blank" style="color:var(--lp-accent);font-weight:500;text-decoration:none;"&gt;${p.title}&lt;/a&gt;
                ${takeHome ? `&lt;div style="font-size:0.78rem;color:var(--lp-text-muted);margin-top:4px;font-style:italic;line-height:1.4;"&gt;💡 ${takeHome}&lt;/div&gt;` : ''}
              &lt;/td&gt;
              &lt;td style="padding:8px 8px;vertical-align:top;"&gt;${diffBadge(p.difficulty)}&lt;/td&gt;
              &lt;td style="padding:8px 8px;text-align:center;vertical-align:top;"&gt;${statusIcon(s.solved)}&lt;/td&gt;
              &lt;td style="padding:8px 8px;text-align:center;vertical-align:top;"&gt;
                ${statusIcon(s.reviewed)}
                ${grade ? `&lt;span style="display:inline-block;background:var(--lp-accent);color:white;padding:1px 6px;border-radius:6px;font-size:0.72rem;font-weight:700;margin-left:4px;vertical-align:middle;"&gt;${grade}&lt;/span&gt;` : ''}
              &lt;/td&gt;
            &lt;/tr&gt;`
    }

    html_out += `
          &lt;/tbody&gt;
        &lt;/table&gt;

        &lt;!-- Flashcards --&gt;
        &lt;p style="font-size:0.78rem;font-weight:700;color:var(--lp-text-faint);text-transform:uppercase;letter-spacing:0.07em;margin:0 0 0.4rem;"&gt;🧠 Flashcards&lt;/p&gt;
        &lt;p style="font-size:0.86rem;color:var(--lp-text-soft);margin:0 0 1.1rem;"&gt;&lt;strong&gt;${week.cards.count} new cards&lt;/strong&gt; — ${week.cards.topics}&lt;/p&gt;

        &lt;!-- System Design --&gt;
        &lt;p style="font-size:0.78rem;font-weight:700;color:var(--lp-text-faint);text-transform:uppercase;letter-spacing:0.07em;margin:0 0 0.4rem;"&gt;🏗️ System Design&lt;/p&gt;`

    if (week.systemDesign) {
      const d = dm[week.systemDesign.slug] || {}
      html_out += `
        &lt;p style="font-size:0.86rem;color:var(--lp-text-soft);margin:0;"&gt;
          &lt;a href="https://github.com/PierpaoloV/learning/tree/main/system-design/${week.systemDesign.slug}" target="_blank" style="color:var(--lp-accent);font-weight:500;text-decoration:none;"&gt;${week.systemDesign.title}&lt;/a&gt;
          &nbsp;${statusIcon(d.written)}
        &lt;/p&gt;`
    } else {
      html_out += `&lt;p style="font-size:0.86rem;color:var(--lp-text-faint);margin:0;"&gt;—&lt;/p&gt;`
    }

    html_out += `
      &lt;/div&gt;
      &lt;/details&gt;`
  }

  html_out += `
      &lt;/div&gt;
      &lt;/details&gt;
    &lt;/div&gt;
    &lt;/details&gt;

  &lt;/div&gt;`

  const container = document.createElement("div");
  container.innerHTML = html_out;
  return container;
}
